/* ==========================================================================
   SKIN: Windows XP (Luna)   ·   [data-skin="xp"]
   Authentic Luna blue title gradients, glossy white-to-putty controls, putty
   greys and beveled chrome. Pure CSS over stock shadcn (+ the generic shell).
   Every brand-critical value is tokenized as a tunable knob and consumed
   through var()/calc() so the editor genuinely retunes the skin.
   ========================================================================== */

:root[data-skin="xp"] {
  --app-font-sans: "Tahoma", "Verdana", "Geneva", "DejaVu Sans", "Segoe UI", sans-serif;
  --app-font-heading: var(--app-font-sans);
  --app-font-mono: "Lucida Console", "DejaVu Sans Mono", "Courier New", monospace;
  --app-font-size: 13px;

  /* ---- TUNABLE SHAPE KNOBS (driven by the editor sliders) -------------- */
  --xp-radius: 3px;            /* Luna control corner radius (buttons/inputs)  */
  --xp-window-radius: 8px;     /* rounded TOP corners of windows / title bars  */
  --xp-bevel: 1px;            /* bevel thickness on raised/sunken controls    */
  --xp-titlebar-gloss: 0.5;   /* strength of the glossy highlight band        */
  --xp-elevation: 4px;        /* drop-shadow depth under windows / menus      */
  --xp-titlebar-h: 8%;        /* height of the bright Luna highlight stop      */

  /* ---- Semantic tokens (route brand hex through these) ----------------- */
  --background: #d4d0c8;
  --foreground: #1a1a1a;
  --card: #ece9d8;
  --card-foreground: #1a1a1a;
  --popover: #ffffff;
  --popover-foreground: #1a1a1a;
  --primary: #0a51c4;            /* Luna blue */
  --primary-foreground: #ffffff;
  --secondary: #ece9d8;
  --secondary-foreground: #1a1a1a;
  --muted: #d4d0c8;
  --muted-foreground: #4a4a44;
  --accent: #316ac5;             /* selection / highlight blue */
  --accent-foreground: #ffffff;
  --destructive: #b41a13;
  --border: #808080;
  --input: #808080;
  --ring: #0a51c4;
  --chart-1: #0a51c4;
  --chart-2: #3a6ea5;
  --chart-3: #1f8a1f;
  --chart-4: #c08000;
  --chart-5: #b41a13;
  --sidebar: #ece9d8;
  --sidebar-foreground: #1a1a1a;
  --sidebar-accent: #316ac5;
  --sidebar-accent-foreground: #ffffff;
  --sidebar-border: #808080;
  --radius: var(--xp-radius);

  /* ---- XP surface palette --------------------------------------------- */
  --xp-face: var(--card);
  --xp-desktop: var(--background);
  --xp-selection: var(--accent);
  --xp-hilite: #ffffff;
  --xp-hilite-soft: color-mix(in srgb, var(--xp-hilite) 75%, var(--xp-face));
  --xp-link: #0000ee;            /* classic hyperlink blue (link variant)    */
  --xp-shadow: var(--border);
  --xp-shadow-deep: #404040;
  --xp-progress: var(--chart-3);
  --xp-hover-glow: #ffc73c;      /* Luna hover orange (border + inner glow)  */
  --xp-hover-glow-deep: #a36a00; /* deep end of the hover-glow derivations   */
  --xp-check: #21a121;           /* authentic Luna green check / radio dot   */
  --xp-destructive-hot: #ff6a4a; /* hot core of the glossy red gradients     */
  --xp-ink-navy: #00264a;        /* dark navy ink mixed into Luna borders    */
  /* shared glossy red face: close button + destructive button */
  --xp-destructive-face: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--destructive) 35%, #fff) 0%,
    color-mix(in srgb, var(--destructive) 80%, var(--xp-destructive-hot)) 50%,
    var(--destructive) 100%
  );

  /* ---- Authentic Luna blue title gradient (tokenized knob) ------------ */
  --xp-titlebar-a: #0997ff;
  --xp-titlebar-b: #0053ee;
  --xp-titlebar-c: #0855dd;
  --xp-titlebar: linear-gradient(
    to bottom,
    var(--xp-titlebar-a) 0%,
    var(--xp-titlebar-b) var(--xp-titlebar-h),
    color-mix(in srgb, var(--xp-titlebar-b) 85%, var(--xp-titlebar-c)) 40%,
    color-mix(in srgb, var(--xp-titlebar-b) 72%, var(--xp-titlebar-a)) 88%,
    var(--xp-titlebar-c) 100%
  );
  --xp-titlebar-gloss-shadow:
    inset 0 1px 0 0 rgba(255, 255, 255, var(--xp-titlebar-gloss)),
    inset 0 -1px 0 0 rgba(0, 0, 0, 0.18);

  /* ---- Glossy Luna control face (white-to-putty) ---------------------- */
  --xp-control-face: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--xp-hilite) 99%, var(--xp-face)) 0%,
    color-mix(in srgb, var(--xp-hilite) 55%, var(--xp-face)) 45%,
    var(--xp-face) 100%
  );
  --xp-control-face-hover: linear-gradient(to bottom, #ffffff 0%, #fbf6e3 45%, #f3efd8 100%);

  /* ---- Bevels composed from the --xp-bevel knob ----------------------- */
  --xp-bevel-raised:
    inset var(--xp-bevel) var(--xp-bevel) 0 0 var(--xp-hilite),
    inset calc(-1 * var(--xp-bevel)) calc(-1 * var(--xp-bevel)) 0 0 var(--xp-shadow-deep),
    inset calc(2 * var(--xp-bevel)) calc(2 * var(--xp-bevel)) 0 0 var(--xp-hilite-soft),
    inset calc(-2 * var(--xp-bevel)) calc(-2 * var(--xp-bevel)) 0 0 var(--xp-shadow);
  --xp-bevel-sunken:
    inset var(--xp-bevel) var(--xp-bevel) 0 0 var(--xp-shadow-deep),
    inset calc(-1 * var(--xp-bevel)) calc(-1 * var(--xp-bevel)) 0 0 var(--xp-hilite),
    inset calc(2 * var(--xp-bevel)) calc(2 * var(--xp-bevel)) 0 0 var(--xp-shadow),
    inset calc(-2 * var(--xp-bevel)) calc(-2 * var(--xp-bevel)) 0 0 var(--xp-hilite-soft);
  --xp-bevel-field:
    inset var(--xp-bevel) var(--xp-bevel) 0 0 var(--xp-shadow),
    inset calc(-1 * var(--xp-bevel)) calc(-1 * var(--xp-bevel)) 0 0 var(--xp-hilite),
    inset calc(2 * var(--xp-bevel)) calc(2 * var(--xp-bevel)) 0 0 var(--xp-shadow-deep),
    inset calc(-2 * var(--xp-bevel)) calc(-2 * var(--xp-bevel)) 0 0 var(--xp-hilite-soft);
  --xp-bevel-window:
    inset var(--xp-bevel) var(--xp-bevel) 0 0 var(--xp-hilite),
    inset calc(-1 * var(--xp-bevel)) calc(-1 * var(--xp-bevel)) 0 0 var(--xp-shadow);

  --xp-window-drop: calc(var(--xp-elevation) * 0.75) var(--xp-elevation)
    calc(var(--xp-elevation) * 2.5) rgba(0, 0, 0, 0.35);
}

[data-skin="xp"] body {
  background: var(--xp-desktop);
  font-size: var(--app-font-size);
  color: var(--foreground);
}
[data-skin="xp"] ::selection { background: var(--xp-selection); color: var(--accent-foreground); }

/* ---- Shell → window chrome --------------------------------------------- */
[data-skin="xp"] .app {
  max-width: 1000px;
  padding: 28px 16px 40px;
}
[data-skin="xp"] .app-bar {
  background: var(--xp-face);
  border: 0;
  border-radius: var(--xp-window-radius) var(--xp-window-radius) 0 0;
  box-shadow: var(--xp-bevel-window);
  backdrop-filter: none;
  margin-bottom: 10px;
  padding: 4px 8px;
}
[data-skin="xp"] .app-brand { font-weight: 700; }

[data-skin="xp"] .stage {
  background: var(--xp-face);
  border: 1px solid var(--primary);
  border-radius: var(--xp-window-radius) var(--xp-window-radius) 0 0;
  box-shadow: inset 0 0 0 1px var(--primary), var(--xp-window-drop);
}
[data-skin="xp"] .stage-head {
  display: flex;
  align-items: center;
  padding: 4px 4px 4px 8px;
  color: #fff;
  font-weight: 700;
  font-size: 12px;
  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.45);
  background: var(--xp-titlebar);
  border-radius: calc(var(--xp-window-radius) - 1px) calc(var(--xp-window-radius) - 1px) 0 0;
  box-shadow: var(--xp-titlebar-gloss-shadow);
}
[data-skin="xp"] .stage-head-buttons { display: inline-flex; gap: 2px; }
[data-skin="xp"] .stage-head-buttons span {
  width: 21px;
  height: 19px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  line-height: 1;
  color: #fff;
  border-radius: var(--xp-radius);
  /* min/max → blue glass derived from the titlebar tokens */
  background: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--xp-titlebar-a) 65%, #fff) 0%,
    color-mix(in srgb, var(--xp-titlebar-b) 80%, var(--xp-titlebar-a)) 50%,
    color-mix(in srgb, var(--xp-titlebar-c) 88%, #000) 100%
  );
  border: 1px solid;
  border-color: color-mix(in srgb, var(--xp-titlebar-a) 40%, #fff)
    color-mix(in srgb, var(--xp-titlebar-c) 62%, #000)
    color-mix(in srgb, var(--xp-titlebar-c) 62%, #000)
    color-mix(in srgb, var(--xp-titlebar-a) 40%, #fff);
  box-shadow: inset 0 1px 0 0 rgba(255, 255, 255, 0.5);
}
/* iconic XP red close button */
[data-skin="xp"] .stage-head-buttons span:last-child {
  background: var(--xp-destructive-face);
  border-color: color-mix(in srgb, var(--destructive) 32%, #fff)
    color-mix(in srgb, var(--destructive) 72%, #000)
    color-mix(in srgb, var(--destructive) 72%, #000)
    color-mix(in srgb, var(--destructive) 32%, #fff);
  border-radius: var(--xp-radius);
}
[data-skin="xp"] .app-main { padding: 10px; gap: 10px; }
[data-skin="xp"] .app-nav { top: 84px; }
[data-skin="xp"] .app-nav-inner {
  background: var(--popover);
  border: 0;
  border-radius: var(--xp-radius);
  box-shadow: var(--xp-bevel-field);
  padding: 2px;
  gap: 0;
  overflow: hidden;
}
[data-skin="xp"] .app-nav-title {
  color: #fff;
  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.45);
  background: var(--xp-titlebar);
  box-shadow: var(--xp-titlebar-gloss-shadow);
  text-transform: none;
  letter-spacing: 0;
  font-weight: 700;
  padding: 3px 8px;
  margin: -2px -2px 2px;
}
[data-skin="xp"] .app-nav a {
  border-radius: var(--xp-radius);
  font-size: 12px;
  padding: 3px 8px;
}
[data-skin="xp"] .app-nav a:hover { background: var(--xp-selection); color: var(--accent-foreground); }

[data-skin="xp"] .gallery { gap: 8px; }

/* Hero → Luna task panel (putty face + blue caption bar) */
[data-skin="xp"] .hero {
  background: var(--xp-face);
  color: var(--foreground);
  border: 0;
  border-radius: var(--xp-window-radius) var(--xp-window-radius) var(--xp-radius) var(--xp-radius);
  box-shadow: var(--xp-bevel-window), var(--xp-window-drop);
  padding: 0;
  overflow: hidden;
}
[data-skin="xp"] .hero-kicker {
  display: block;
  color: #fff;
  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.45);
  background: var(--xp-titlebar);
  box-shadow: var(--xp-titlebar-gloss-shadow);
  border-radius: calc(var(--xp-window-radius) - 1px) calc(var(--xp-window-radius) - 1px) 0 0;
  font-weight: 700;
  font-size: 13px;
  padding: 4px 10px;
  margin: 0 0 12px;
}
[data-skin="xp"] .hero-title { color: var(--primary); padding: 0 16px; }
[data-skin="xp"] .hero-sub {
  color: var(--muted-foreground);
  font-size: 12.5px;
  padding: 4px 16px 16px;
}

/* Specimen → XP task panel with gradient caption */
[data-skin="xp"] .specimen {
  border: 1px solid var(--xp-shadow);
  border-radius: var(--xp-window-radius) var(--xp-window-radius) var(--xp-radius) var(--xp-radius);
  background: var(--xp-face);
  box-shadow: inset 1px 1px 0 0 var(--xp-hilite);
  overflow: hidden;
}
[data-skin="xp"] .specimen-head {
  padding: 3px 8px;
  color: #fff;
  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.45);
  border-bottom: 0;
  background: var(--xp-titlebar);
  border-radius: calc(var(--xp-window-radius) - 1px) calc(var(--xp-window-radius) - 1px) 0 0;
  box-shadow: var(--xp-titlebar-gloss-shadow);
}
[data-skin="xp"] .specimen-title { font-size: 11px; font-weight: 700; }
[data-skin="xp"] .specimen-tag {
  font-size: 10px;
  font-style: italic;
  color: color-mix(in srgb, var(--xp-titlebar-a) 25%, #fff);
}
[data-skin="xp"] .specimen-body { padding: 14px; }

[data-skin="xp"] .app-status {
  border: 0;
  border-radius: 0 0 var(--xp-window-radius) var(--xp-window-radius);
  background: var(--xp-face);
  border-top: 1px solid var(--xp-hilite);
  box-shadow: none;
  color: var(--muted-foreground);
  margin-top: 0;
  padding: 2px 3px;
  gap: 3px;
}
[data-skin="xp"] .app-status > * {
  padding: 1px 8px;
  box-shadow: inset 1px 1px 0 0 var(--xp-shadow), inset -1px -1px 0 0 var(--xp-hilite);
}

/* ---- Controls ----------------------------------------------------------- */
[data-skin="xp"] .group\/button {
  border: 1px solid color-mix(in srgb, var(--primary) 50%, var(--xp-ink-navy));
  border-radius: var(--xp-radius);
  background: var(--xp-control-face);
  color: var(--foreground);
  box-shadow: inset 0 1px 0 0 #fff, inset 0 -1px 0 0 rgba(0, 0, 0, 0.08);
  transition: none;
}
[data-skin="xp"] .group\/button:hover {
  background: var(--xp-control-face-hover);
  border-color: color-mix(in srgb, var(--xp-hover-glow) 60%, var(--xp-hover-glow-deep));
  box-shadow: inset 0 0 0 1px var(--xp-hover-glow),
    inset 0 -2px 0 0 color-mix(in srgb, var(--xp-hover-glow) 78%, var(--xp-hover-glow-deep));
}
[data-skin="xp"] .group\/button:active:not(:disabled),
[data-skin="xp"] .group\/button[data-state="open"],
[data-skin="xp"] .group\/button[aria-expanded="true"] {
  background: linear-gradient(to bottom, var(--xp-face), color-mix(in srgb, var(--xp-face) 85%, #fff));
  box-shadow: var(--xp-bevel-sunken);
}
[data-skin="xp"] .group\/button:focus-visible {
  outline: 1px dotted color-mix(in srgb, var(--ring) 75%, #000);
  outline-offset: -4px;
  border-color: color-mix(in srgb, var(--ring) 50%, var(--xp-ink-navy));
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--ring) 45%, transparent);
}
/* DEFAULT → primary affordance: Luna blue inner glow ring + dark navy border */
[data-skin="xp"] .group\/button[data-variant="default"] {
  font-weight: 700;
  border-color: color-mix(in srgb, var(--primary) 50%, var(--xp-ink-navy));
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--primary) 55%, #fff),
    inset 0 -2px 0 0 color-mix(in srgb, var(--primary) 35%, transparent);
}
[data-skin="xp"] .group\/button[data-variant="default"]:hover {
  box-shadow: inset 0 0 0 1px var(--xp-hover-glow),
    inset 0 -2px 0 0 color-mix(in srgb, var(--xp-hover-glow) 78%, var(--xp-hover-glow-deep));
}
/* SECONDARY → plain putty face, no extra emphasis */
[data-skin="xp"] .group\/button[data-variant="secondary"] {
  background: linear-gradient(to bottom, color-mix(in srgb, var(--xp-face) 80%, #fff), var(--xp-face));
  border-color: color-mix(in srgb, var(--border) 80%, var(--xp-face));
  font-weight: 400;
}
/* OUTLINE → flat white field with thin ink border (distinct from secondary) */
[data-skin="xp"] .group\/button[data-variant="outline"] {
  background: #fff;
  border: 1px solid var(--border);
  box-shadow: none;
  color: var(--foreground);
}
[data-skin="xp"] .group\/button[data-variant="outline"]:hover {
  background: color-mix(in srgb, var(--accent) 8%, #fff);
  border-color: var(--accent);
}
/* DESTRUCTIVE → glossy XP red, derived from --destructive */
[data-skin="xp"] .group\/button[data-variant="destructive"] {
  background: var(--xp-destructive-face);
  border-color: color-mix(in srgb, var(--destructive) 32%, #fff)
    color-mix(in srgb, var(--destructive) 72%, #000)
    color-mix(in srgb, var(--destructive) 72%, #000)
    color-mix(in srgb, var(--destructive) 32%, #fff);
  color: #fff;
  font-weight: 700;
  text-shadow: 0 1px 1px rgba(0, 0, 0, 0.4);
  box-shadow: inset 0 1px 0 0 rgba(255, 255, 255, 0.4);
}
[data-skin="xp"] .group\/button[data-variant="destructive"]:hover {
  background: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--destructive) 28%, #fff) 0%,
    color-mix(in srgb, var(--destructive) 70%, color-mix(in srgb, var(--xp-destructive-hot) 80%, #fff)) 50%,
    color-mix(in srgb, var(--destructive) 88%, var(--xp-destructive-hot)) 100%
  );
}
[data-skin="xp"] .group\/button[data-variant="link"] {
  background: transparent;
  border: 0;
  box-shadow: none;
  color: var(--xp-link);
  text-decoration: underline;
}
/* GHOST → borderless, hover paints the XP selection bar */
[data-skin="xp"] .group\/button[data-variant="ghost"] {
  background: transparent;
  border: 0;
  box-shadow: none;
  color: var(--foreground);
}
[data-skin="xp"] .group\/button[data-variant="ghost"]:hover {
  background: var(--xp-selection);
  color: var(--accent-foreground);
}
/* DISABLED → flat putty, embossed grey label, no bevel/gloss (any variant) */
[data-skin="xp"] .group\/button:disabled,
[data-skin="xp"] .group\/button[disabled],
[data-skin="xp"] .group\/button[aria-disabled="true"] {
  background: var(--xp-face);
  border-color: color-mix(in srgb, var(--border) 55%, var(--xp-face));
  color: var(--muted-foreground);
  text-shadow: 0 1px 0 #fff;
  box-shadow: none;
}

[data-skin="xp"] [data-slot="input"],
[data-skin="xp"] [data-slot="textarea"],
[data-skin="xp"] [data-slot="select-trigger"],
[data-skin="xp"] .skin-select {
  border: 0;
  border-radius: var(--xp-radius);
  background-color: var(--popover);
  color: var(--popover-foreground);
  box-shadow: var(--xp-bevel-field);
}
[data-skin="xp"] [data-slot="input"]:focus-visible,
[data-skin="xp"] [data-slot="textarea"]:focus-visible,
[data-skin="xp"] [data-slot="select-trigger"]:focus-visible {
  outline: 1px dotted var(--ring);
  outline-offset: -3px;
}

[data-skin="xp"] [data-slot="card"] {
  border: 0;
  border-radius: var(--xp-window-radius) var(--xp-window-radius) var(--xp-radius) var(--xp-radius);
  background-color: var(--xp-face);
  box-shadow: var(--xp-bevel-window);
}

[data-skin="xp"] [data-slot="popover-content"],
[data-skin="xp"] [data-slot="dropdown-menu-content"],
[data-skin="xp"] [data-slot="context-menu-content"],
[data-skin="xp"] [data-slot="menubar-content"],
[data-skin="xp"] [data-slot="select-content"],
[data-skin="xp"] [data-slot="command"],
[data-skin="xp"] [data-slot="hover-card-content"] {
  border: 1px solid var(--xp-shadow);
  border-radius: var(--xp-radius);
  box-shadow: inset 1px 1px 0 0 var(--xp-hilite),
    calc(var(--xp-elevation) * 0.5) calc(var(--xp-elevation) * 0.5) 0 0 rgba(0, 0, 0, 0.35);
  background-color: var(--popover);
}
[data-skin="xp"] [data-slot="tooltip-content"] {
  border-radius: var(--xp-radius);
  background-color: #ffffe1;
  color: #000;
  border: 1px solid #000;
}
[data-skin="xp"] [data-slot="tooltip-content"] svg { fill: #ffffe1; }

[data-skin="xp"] [data-slot="dropdown-menu-item"][data-highlighted],
[data-skin="xp"] [data-slot="context-menu-item"][data-highlighted],
[data-skin="xp"] [data-slot="select-item"][data-highlighted],
[data-skin="xp"] [data-slot="command-item"][data-selected="true"] {
  border-radius: var(--xp-radius);
  background-color: var(--xp-selection);
  color: var(--accent-foreground);
}

[data-skin="xp"] [data-slot="dialog-content"],
[data-skin="xp"] [data-slot="alert-dialog-content"],
[data-skin="xp"] [data-slot="sheet-content"] {
  border-radius: var(--xp-window-radius) var(--xp-window-radius) var(--xp-radius) var(--xp-radius);
  background-color: var(--xp-face);
  border: 1px solid var(--primary);
  box-shadow: inset 0 0 0 1px var(--xp-hilite), var(--xp-window-drop);
}

[data-skin="xp"] [data-slot="checkbox"] {
  border: 0;
  border-radius: var(--xp-radius);
  background-color: var(--popover);
  box-shadow: var(--xp-bevel-field);
  color: var(--xp-check);
}
[data-skin="xp"] [data-slot="radio-group-item"] {
  border: 0;
  background-color: var(--popover);
  box-shadow:
    inset 1px 1px 0 0 var(--xp-shadow),
    inset -1px -1px 0 0 var(--xp-hilite),
    0 0 0 1px var(--xp-shadow-deep);
  color: var(--xp-check);
}

[data-skin="xp"] [data-slot="tabs-list"] {
  border-radius: 0;
  background: transparent;
  gap: 2px;
  padding: 0;
  align-items: flex-end;
  border-bottom: 1px solid var(--xp-shadow);
}
[data-skin="xp"] [data-slot="tabs-trigger"] {
  border-radius: var(--xp-radius) var(--xp-radius) 0 0;
  color: var(--foreground);
  padding: 3px 12px;
  background: linear-gradient(to bottom, color-mix(in srgb, var(--xp-hilite) 55%, var(--xp-face)), var(--xp-face));
  border: 1px solid var(--xp-shadow);
  border-bottom: 0;
  box-shadow: inset 1px 1px 0 0 var(--xp-hilite);
  margin-top: 2px;
}
[data-skin="xp"] [data-slot="tabs-trigger"][data-state="active"] {
  background: var(--xp-face);
  position: relative;
  z-index: 1;
  margin-top: 0;
  margin-bottom: -1px;
  padding-bottom: 4px;
  font-weight: 700;
}

/* Switch → sunken putty track off, glossy Luna blue track on, raised thumb */
[data-skin="xp"] [data-slot="switch"] {
  border: 0;
  border-radius: 9999px;
  background: var(--muted);
  box-shadow: var(--xp-bevel-field);
}
[data-skin="xp"] [data-slot="switch"][data-state="checked"] {
  background: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--primary) 60%, #fff),
    var(--primary)
  );
}
[data-skin="xp"] [data-slot="switch"]:focus-visible {
  outline: 1px dotted color-mix(in srgb, var(--ring) 75%, #000);
  outline-offset: 2px;
}
[data-skin="xp"] [data-slot="switch-thumb"] {
  border: 0;
  border-radius: 9999px;
  background: var(--xp-control-face);
  box-shadow: var(--xp-bevel-raised);
}

/* Badges → each variant reads as a distinct Luna pill */
[data-skin="xp"] [data-slot="badge"] { border-radius: var(--xp-radius); }
[data-skin="xp"] [data-slot="badge"][data-variant="secondary"] {
  background: var(--xp-control-face);
  border: 1px solid var(--border);
  color: var(--secondary-foreground);
}
[data-skin="xp"] [data-slot="badge"][data-variant="outline"] {
  background: var(--popover);
  border: 1px solid var(--border);
  color: var(--foreground);
}
[data-skin="xp"] [data-slot="badge"][data-variant="destructive"] {
  background: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--destructive) 70%, color-mix(in srgb, var(--xp-destructive-hot) 80%, #fff)),
    var(--destructive)
  );
  border: 1px solid color-mix(in srgb, var(--destructive) 72%, #000);
  color: #fff;
}

[data-skin="xp"] [data-slot="progress"] {
  border-radius: var(--xp-radius);
  background-color: var(--popover);
  box-shadow: var(--xp-bevel-field);
}
[data-skin="xp"] [data-slot="progress-indicator"] {
  border-radius: 0;
  background: linear-gradient(to bottom, color-mix(in srgb, var(--xp-progress) 70%, #fff), var(--xp-progress));
}

[data-skin="xp"] [data-slot="slider-track"] {
  border-radius: var(--xp-radius);
  box-shadow: var(--xp-bevel-field);
  background-color: var(--popover);
}
[data-skin="xp"] [data-slot="slider-thumb"] {
  border-radius: var(--xp-radius);
  background: var(--xp-control-face);
  box-shadow: var(--xp-bevel-raised);
  border: 0;
}
